using System.Collections.Generic;
using System.Linq;
using System.Web.Mvc;
using YourNamespace.Models; // Adjust the namespace as necessary

public class ReviewsController : Controller
{
    private readonly YourDbContext _context;

    public ReviewsController()
    {
        _context = new YourDbContext();
    }

    public ActionResult ProductReviews(int productId)
    {
        var reviews = _context.Reviews
            .Where(r => r.ProductId == productId)
            .ToList();

        return View(reviews);
    }
}

// Review model
public class Review
{
    public int Id { get; set; }
    public int ProductId { get; set; }
    public string UserName { get; set; }
    public string Content { get; set; }
}

// Razor view (ProductReviews.cshtml)
@model IEnumerable<YourNamespace.Models.Review>

<h2>User Reviews</h2>
@foreach (var review in Model)
{
    <div class="review">
        <strong>@Html.Encode(review.UserName)</strong>
        <p>@Html.Raw(System.Net.WebUtility.HtmlEncode(review.Content))</p>
    </div>
}